import{_ as s,o as e,c as a,ai as t}from"./chunks/framework.B3x_xFnx.js";const c=JSON.parse('{"title":"Guide to Building PixelOS","description":"","frontmatter":{},"headers":[],"relativePath":"JoinTheTeam/BuildingPixelOS.md","filePath":"JoinTheTeam/BuildingPixelOS.md"}'),n={name:"JoinTheTeam/BuildingPixelOS.md"};function l(h,i,p,d,r,o){return e(),a("div",null,[...i[0]||(i[0]=[t(`<h1 id="guide-to-building-pixelos" tabindex="-1">Guide to Building PixelOS <a class="header-anchor" href="#guide-to-building-pixelos" aria-label="Permalink to “Guide to Building PixelOS”">​</a></h1><p>This guide provides a step-by-step tutorial on setting up a build environment for building PixelOS on Ubuntu and syncing the ROM from the manifest.</p><h2 id="step-1-install-necessary-tools-and-dependencies" tabindex="-1">Step 1: Install Necessary Tools and Dependencies <a class="header-anchor" href="#step-1-install-necessary-tools-and-dependencies" aria-label="Permalink to “Step 1: Install Necessary Tools and Dependencies”">​</a></h2><p>Ensure you have the necessary tools and dependencies installed on your system, including the Java Development Kit (JDK), the Android SDK, Git, and Repo. Open a terminal and run the following command:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt-get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt-get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bison</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build-essential</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> flex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> g++-multilib</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gcc-multilib</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git-lfs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gnupg</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gperf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lib32ncurses-dev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lib32readline-dev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lib32z1-dev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libelf-dev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> liblz4-tool</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libncurses-dev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libssl-dev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libxml2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libxml2-utils</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lzop</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openjdk-21-jdk</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pngcrush</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> protobuf-compiler</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> python3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> repo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> unzip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xsltproc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> zip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> zlib1g-dev</span></span></code></pre></div><p>Alternatively, for a simpler method, run:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wget</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/akhilnarang/scripts/master/setup/android_build_env.sh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> android_build_env.sh</span></span></code></pre></div><p>If you run into the <code>Build sandboxing disabled due to nsjail error</code> message during builds, run:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sysctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -w</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kernel.apparmor_restrict_unprivileged_userns=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span></span></code></pre></div><p>This fixes the <code>07:37:33 Build sandboxing disabled due to nsjail error</code> issue on systems where AppArmor blocks unprivileged user namespaces.</p><h2 id="step-2-sync-pixelos-rom-using-repo" tabindex="-1">Step 2: Sync PixelOS ROM Using Repo <a class="header-anchor" href="#step-2-sync-pixelos-rom-using-repo" aria-label="Permalink to “Step 2: Sync PixelOS ROM Using Repo”">​</a></h2><p>Once your build environment is set up, use Repo to sync the PixelOS ROM from the manifest. Create a directory to store the PixelOS source code and run the following commands:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pixelos</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pixelos</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">repo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/PixelOS-AOSP/android_manifest.git</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -b</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sixteen-qpr2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --git-lfs</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">repo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sync</span></span></code></pre></div><p>This initializes the Repo tool and syncs the <code>sixteen</code> version of the PixelOS ROM from the manifest. The process may take some time, depending on your disk and internet connection speed.</p><h2 id="step-3-download-device-specific-source-code" tabindex="-1">Step 3: Download Device-Specific Source Code <a class="header-anchor" href="#step-3-download-device-specific-source-code" aria-label="Permalink to “Step 3: Download Device-Specific Source Code”">​</a></h2><p>To download the device-specific source code for the PixelOS ROM, use the <code>git clone</code> command and sync the device sources to their respective folders.</p><h2 id="step-4-build-the-rom" tabindex="-1">Step 4: Build the ROM <a class="header-anchor" href="#step-4-build-the-rom" aria-label="Permalink to “Step 4: Build the ROM”">​</a></h2><p>After downloading the device-specific source code, use the <code>breakfast</code> and <code>m</code> commands to build the ROM. For example, to build PixelOS for the device codenamed <code>xaga</code> with the build type set to <code>user</code>:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">breakfast</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xaga</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pixelos</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -j$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nproc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --all)</span></span></code></pre></div><p>Change <code>user</code> to <code>userdebug</code> or <code>eng</code> if you want to build a debug or engineering build.</p><h2 id="step-5-locate-the-built-rom" tabindex="-1">Step 5: Locate the Built ROM <a class="header-anchor" href="#step-5-locate-the-built-rom" aria-label="Permalink to “Step 5: Locate the Built ROM”">​</a></h2><p>After the build process is complete, you should have a working zip file of the PixelOS ROM. You can find it at <code>./out/target/product/xaga/PixelOS_*.zip</code> (replace <code>xaga</code> with the codename for your device).</p><p>You can flash this zip to your device using the appropriate tools, such as PixelOS Recovery or TWRP.</p>`,23)])])}const F=s(n,[["render",l]]);export{c as __pageData,F as default};
